// HMAC verification + DEVELOPER_MODE check
const crypto = require('crypto');
const raw = $input.first().binary ? Buffer.from($input.first().binary['data'].data, 'base64') : Buffer.from(JSON.stringify($input.first().json));
const sigHeader = $json["headers"]?.["x-evez-sig"] || $json["headers"]?.["X-EVEZ-SIG"] || $json["headers"]?.["X-Evez-Sig"] || '';
const secret = process.env.HMAC_SECRET || '';
const dev = (process.env.DEVELOPER_MODE || '').toLowerCase() === 'true';

function safeCompare(a, b) {
  if (!a || !b || a.length !== b.length) return false;
  const bufA = Buffer.from(a);
  const bufB = Buffer.from(b);
  return crypto.timingSafeEqual(bufA, bufB);
}

let verified = false;
if (dev) {
  verified = true; // developer mode bypass
} else if (secret && sigHeader) {
  const h = crypto.createHmac('sha256', secret).update(raw).digest('hex');
  verified = safeCompare(h, sigHeader);
}

if (!verified) {
  return [{ json: { status: 'rejected', reason: 'invalid_signature_or_missing', dev_bypass: dev } }];
}

// Normalized payload
const payload = $input.first().json || JSON.parse(raw.toString());
// Attach metadata
payload._ingest_ts = new Date().toISOString();
return [{ json: { status: 'verified', payload } }];

// Decision: if action requires approval, enqueue; else forward immediately
const p = $input.first().json.payload || {};
// Simple conservative rule for sandbox: any payload with action:'spawn' or eventType:'FIRE' goes to approval
const isSpawn = (p.action || p.eventType || '').toString().toLowerCase().includes('spawn');
const isFire = (p.eventType || p.action || '').toString().toUpperCase().includes('FIRE');
const dev = (process.env.DEVELOPER_MODE || '').toLowerCase() === 'true';

if ((isSpawn || isFire) && !dev) {
  const id = 'pending_' + Date.now() + '_' + Math.floor(Math.random()*10000);
  // store minimal queue entry in memory by returning to the workflow output; operator calls /approve with id
  return [{ json: { queued: true, id, payload: p, ts: new Date().toISOString() } }];
}

// Fast-forward (dev or non-critical)
// Forward to target: by default forward to provided target_forward_url in payload, or to an environment variable FORWARD_TARGET
const forwardUrl = p.target_forward_url || process.env.FORWARD_TARGET || '';
if (!forwardUrl) {
  return [{ json: { forwarded: false, reason: 'no_forward_target', payload: p } }];
}

return [{ json: { forward: true, forwardUrl, payload: p } }];

